.dynamic-headline {
  font-family: 'Inter var', sans-serif;
  font-weight: 550; /* Fallback for non-variable font or simpler control */
  font-variation-settings: 'wght' 550, 'wdth' 105, 'slnt' -7;
  /* Adjust 'wght' (weight), 'wdth' (width), 'slnt' (slant) as needed. */
  /* Many other axes like 'opsz' (optical size) or custom axes can exist. */
}

@media (min-width: 768px) {
  .dynamic-headline {
    font-variation-settings: 'wght' 600, 'wdth' 110, 'slnt' 0;
  }
}
